```rust
use std::collections::BinaryHeap;
use std::cmp::Reverse;

pub fn solve(edges: Vec<Vec<i64>>, online: Vec<bool>, k: i64) -> i64 {
    let n = online.len();
    let mut allowed = vec![false; n];
    for i in 0..n {
        if i == 0 || i == n-1 {
            allowed[i] = true;
        } else {
            allowed[i] = online[i];
        }
    }

    let mut max_edge_cost = 0;
    for edge in &edges {
        if edge[2] > max_edge_cost {
            max_edge_cost = edge[2];
        }
    }

    if !check(0, &edges, &allowed, k, n) {
        return -1;
    }

    let mut low = 0;
    let mut high = max_edge_cost + 1;

    while low < high {
        let mid = (low + high) / 2;
        if check(mid, &edges, &allowed, k, n) {
            low = mid + 1;
        } else {
            high = mid;
        }
    }

    low - 1
}

fn check(x: i64, edges: &Vec<Vec<i64>>, allowed: &[bool], k: i64, n: usize) -> bool {
    let mut graph: Vec<Vec<(usize, i64)>> = vec![vec![]; n];
    for edge in edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        let cost_edge = edge[2];
        if allowed[u] && allowed[v] && cost_edge >= x {
            graph[u].push((v, cost_edge));
        }
    }

    let inf = k + 1;
    let mut dist = vec![inf; n];
    let mut heap = BinaryHeap::new();

    dist[0] = 0;
    heap.push(Reverse((0, 0)));

    while let Some(Reverse((cost, u))) = heap.pop() {
        if cost != dist[u] {
            continue;
        }
        if u == n - 1 {
            if cost <= k {
                return true;
            } else {
                return false;
            }
        }
        for &(v, c_edge) in &graph[u] {
            let new_cost = cost + c_edge;
            if new_cost > k {
                continue;
            }
            if new_cost < dist[v] {
                dist[v] = new_cost;
                heap.push(Reverse((new_cost, v)));
            }
        }
    }

    false
}
